#[tauri::command]
fn load_config() -> Result<AppConfig, String> {
    load_or_default_config().map_err(|e| e.to_string())
}

#[tauri::command]
fn save_config(
    app: AppHandle,
    config: AppConfig,
    tray: State<'_, TrayHandles>,
    state: State<'_, SharedRuntimeState>,
) -> Result<String, String> {
    let config = config.canonicalized().map_err(|e| e.to_string())?;
    let path = config
        .save_default_path()
        .map(|path| path.display().to_string())
        .map_err(|e| e.to_string())?;

    // Re-render the tray indicator immediately so a changed display mode / IP prefix is
    // reflected without waiting for the next exit-IP poll (which can be minutes away).
    // Recomputed from the cached exit status — no network lookup needed.
    if let Ok(mut runtime) = state.lock() {
        runtime.exit_status.tray_text =
            geo::tray_indicator_text(&runtime.exit_status, &config.tray_settings);
        let snapshot = RuntimeSnapshot::from(&*runtime);
        update_tray_ui(&app, tray.inner(), &snapshot);
    }

    Ok(path)
}

#[tauri::command]
fn preview_raw_entries(text: String) -> Result<RawImportPreview, String> {
    let entries = parse_raw_import_text(&text).map_err(|e| e.to_string())?;
    let canonical_text = entries
        .iter()
        .map(proxy_core::format_raw_proxy_entry)
        .collect::<Vec<_>>()
        .join("\n");
    Ok(RawImportPreview {
        entries,
        canonical_text,
    })
}

// Async so the blocking daemon socket call runs off the main thread. A synchronous
// command would execute on the Tauri event loop, and this one is polled every few
// seconds — a slow/busy daemon would otherwise freeze the window controls.
#[tauri::command]
async fn status(state: State<'_, SharedRuntimeState>) -> Result<Status, String> {
    let config = load_or_default_config().map_err(|e| e.to_string())?;
    {
        let mut runtime = state
            .lock()
            .map_err(|_| "runtime lock poisoned".to_string())?;
        if runtime
            .active_profile
            .as_ref()
            .map(|profile| profile.routing_mode == RoutingMode::Tun)
            .unwrap_or(false)
        {
            sync_runtime_with_tun_status(&mut runtime);
        }
    }
    let runtime = state
        .lock()
        .map_err(|_| "runtime lock poisoned".to_string())?;
    Ok(Status {
        enabled: config.enabled,
        selected_profile_id: config.selected_profile_id.clone(),
        active_profile_id: runtime.active_profile.as_ref().map(|p| p.id.clone()),
        active_profile_name: runtime.active_profile.as_ref().map(|p| p.name.clone()),
        routing_mode: runtime
            .active_profile
            .as_ref()
            .map(|p| p.routing_mode.to_string())
            .unwrap_or_else(|| "none".to_string()),
        connection_state: runtime.connection_state,
        last_error: runtime.last_error.clone(),
        local_system_proxy_port: runtime.local_system_proxy.as_ref().map(|proxy| proxy.port),
        exit_status: runtime.exit_status.clone(),
        vpn_status: runtime.vpn_status.clone(),
        traffic_flow: runtime.traffic_flow.clone(),
    })
}

#[tauri::command]
fn start_proxy(
    app: AppHandle,
    config: AppConfig,
    profile_id: String,
    tray: State<'_, TrayHandles>,
    state: State<'_, SharedRuntimeState>,
) -> Result<(), String> {
    start_proxy_background(&app, tray.inner(), state.inner(), config, profile_id)
}

fn start_proxy_background(
    app: &AppHandle,
    tray: &TrayHandles,
    state: &SharedRuntimeState,
    config: AppConfig,
    profile_id: String,
) -> Result<(), String> {
    let config = config.canonicalized().map_err(|e| e.to_string())?;
    let profile_id = config
        .profile_by_selector(&profile_id)
        .map_err(|e| e.to_string())?
        .id
        .clone();
    let profile = config
        .resolve_profile_by_selector(Some(&profile_id))
        .map_err(|e| e.to_string())?;

    let snapshot = {
        let mut runtime = state
            .lock()
            .map_err(|_| "runtime lock poisoned".to_string())?;
        runtime.connection_state = ConnectionState::Rebinding;
        runtime.active_profile = Some(profile.clone());
        runtime.last_profile_name = Some(profile.name.clone());
        runtime.last_error = None;
        runtime.exit_status = Default::default();
        runtime.generation += 1;
        runtime.vpn_status = network::build_vpn_status(
            &profile,
            &NetworkSnapshot::default(),
            runtime.connection_state,
        );
        runtime.traffic_flow = network::build_traffic_flow(
            Some(&profile),
            &runtime.vpn_status,
            runtime.connection_state,
        );
        RuntimeSnapshot::from(&*runtime)
    };
    update_tray_ui(app, tray, &snapshot);

    let app = app.clone();
    let tray = tray.clone();
    let state = state.clone();
    std::thread::spawn(move || {
        if let Err(error) = start_proxy_impl(&app, &tray, &state, config, profile_id) {
            set_runtime_error(&app, &error);
        }
    });
    Ok(())
}

fn start_proxy_impl(
    app: &AppHandle,
    tray: &TrayHandles,
    state: &SharedRuntimeState,
    config: AppConfig,
    profile_id: String,
) -> Result<(), String> {
    let mut config = config.canonicalized().map_err(|e| e.to_string())?;
    let profile_id = config
        .profile_by_selector(&profile_id)
        .map_err(|e| e.to_string())?
        .id
        .clone();
    config.enabled = true;
    config.selected_profile_id = Some(profile_id.clone());
    config.active_profile_id = Some(profile_id.clone());
    let config = config.canonicalized().map_err(|e| e.to_string())?;
    let profile = config
        .resolve_profile_by_selector(Some(&profile_id))
        .map_err(|e| e.to_string())?;

    config.save_default_path().map_err(|e| e.to_string())?;
    stop_runtime(app, tray, state)?;

    if profile.routing_mode == RoutingMode::Tun && profile.startup_cleanup_enabled {
        let _ = perform_startup_cleanup();
    }

    {
        let mut runtime = state
            .lock()
            .map_err(|_| "runtime lock poisoned".to_string())?;
        runtime.connection_state = ConnectionState::Rebinding;
        runtime.active_profile = Some(profile.clone());
        runtime.last_profile_name = Some(profile.name.clone());
        runtime.last_error = None;
        runtime.exit_status = Default::default();
        runtime.generation += 1;
        runtime.vpn_status = network::build_vpn_status(
            &profile,
            &NetworkSnapshot::default(),
            runtime.connection_state,
        );
        runtime.traffic_flow = network::build_traffic_flow(
            Some(&profile),
            &runtime.vpn_status,
            runtime.connection_state,
        );
    }

    if profile.routing_mode == RoutingMode::System {
        #[cfg(any(target_os = "linux", target_os = "windows"))]
        let local_server = Some(
            local_socks::start(profile.endpoint.clone()).map_err(|error| {
                let message = error.to_string();
                if let Ok(mut runtime) = state.lock() {
                    runtime.connection_state = ConnectionState::Error;
                    runtime.last_error = Some(message.clone());
                    let snap = RuntimeSnapshot::from(&*runtime);
                    update_tray_ui(app, tray, &snap);
                }
                message
            })?,
        );
        #[cfg(not(any(target_os = "linux", target_os = "windows")))]
        let local_server: Option<proxy_core::LocalSocksServer> = None;

        let snapshot = match system_proxy::enable(&profile) {
            Ok(snapshot) => snapshot,
            Err(error) => {
                if let Some(proxy) = local_server {
                    let _ = proxy.shutdown();
                }
                let message = error.to_string();
                if let Ok(mut runtime) = state.lock() {
                    runtime.connection_state = ConnectionState::Error;
                    runtime.last_error = Some(message.clone());
                    let snap = RuntimeSnapshot::from(&*runtime);
                    update_tray_ui(app, tray, &snap);
                }
                return Err(message);
            }
        };

        // Persist the snapshot so we can restore it after a crash.
        persist_system_snapshot(&snapshot);

        let effective_system_profile = effective_system_lookup_profile(&profile, true);
        let runtime_snapshot = {
            let mut runtime = state
                .lock()
                .map_err(|_| "runtime lock poisoned".to_string())?;
            runtime.system_snapshot = Some(snapshot);
            #[cfg(any(target_os = "linux", target_os = "windows"))]
            if let Some(proxy) = local_server {
                runtime.local_system_proxy = Some(crate::types::LocalSystemProxyRuntime {
                    port: proxy.listen_addr().port(),
                    handle: proxy,
                });
            }
            runtime.connection_state = ConnectionState::Connected;
            runtime.vpn_status = network::build_vpn_status(
                &profile,
                &NetworkSnapshot::default(),
                runtime.connection_state,
            );
            runtime.traffic_flow = network::build_traffic_flow(
                Some(&profile),
                &runtime.vpn_status,
                runtime.connection_state,
            );
            RuntimeSnapshot::from(&*runtime)
        };
        update_tray_ui(app, tray, &runtime_snapshot);

        // Start the exit-status poller for system mode too (state is Connected
        // at this point so the first lookup fires immediately).
        if config.tray_settings.exit_ip_lookup_enabled {
            let generation = {
                let runtime = state
                    .lock()
                    .map_err(|_| "runtime lock poisoned".to_string())?;
                runtime.generation
            };
            start_exit_status_poller(
                app.clone(),
                tray.clone(),
                state.clone(),
                effective_system_profile,
                config.tray_settings.clone(),
                generation,
            )?;
        }
    } else if profile.routing_mode == RoutingMode::Tun {
        #[cfg(target_os = "windows")]
        if !elevation::is_elevated() {
            return Err(
                "Windows TUN routing requires an elevated administrator session. Start the app as administrator before connecting a TUN profile."
                    .to_string(),
            );
        }

        #[cfg(target_os = "windows")]
        guard_windows_wireguard_killswitch()?;

        let generation = {
            let runtime = state
                .lock()
                .map_err(|_| "runtime lock poisoned".to_string())?;
            runtime.generation
        };

        if config.tray_settings.exit_ip_lookup_enabled {
            start_exit_status_poller(
                app.clone(),
                tray.clone(),
                state.clone(),
                profile.clone(),
                config.tray_settings.clone(),
                generation,
            )?;
        }

        #[cfg(target_os = "windows")]
        let mut recovery_watchdog = Some(windows_recovery::TunRecoveryWatchdog::arm(
            &proxy_core::tun::tun_device_name(&profile.id),
        )?);

        let status = match tun_backend::start(profile.clone()) {
            Ok(status) => status,
            Err(error) => {
                #[cfg(target_os = "windows")]
                if let Some(watchdog) = recovery_watchdog.take() {
                    let _ = watchdog.cancel();
                }
                return Err(error.to_string());
            }
        };
        let connected_artifacts = if status.state == "connected" {
            let session_id = crate::util::generate_session_id();
            match crate::types::RuntimeArtifacts::new(
                &session_id,
                &profile,
                status.tun2proxy_pid.unwrap_or_default(),
                status.host_vpn_interface.clone(),
                status.pinned_proxy_routes.clone(),
                status.wfp_filters.clone(),
            )
            .map_err(|error| error.to_string())
            .and_then(|artifacts| {
                persist_runtime_artifacts_state(&profile, &artifacts)?;
                Ok(artifacts)
            }) {
                Ok(artifacts) => Some(artifacts),
                Err(error) => {
                    let _ = tun_backend::stop();
                    #[cfg(target_os = "windows")]
                    if let Some(watchdog) = recovery_watchdog.take() {
                        let _ = watchdog.cancel();
                    }
                    return Err(error);
                }
            }
        } else {
            #[cfg(target_os = "windows")]
            if let Some(watchdog) = recovery_watchdog.take() {
                let _ = watchdog.cancel();
            }
            None
        };
        let runtime_snapshot = {
            let mut runtime = state
                .lock()
                .map_err(|_| "runtime lock poisoned".to_string())?;
            apply_tun_daemon_status(&mut runtime, &status);
            if let Some(artifacts) = connected_artifacts {
                runtime.current_session_id = Some(artifacts.session_id.clone());
                runtime.runtime_artifacts = Some(artifacts);
                #[cfg(target_os = "windows")]
                {
                    runtime.windows_recovery_watchdog = recovery_watchdog.take();
                }
            }
            RuntimeSnapshot::from(&*runtime)
        };
        update_tray_ui(app, tray, &runtime_snapshot);
    }

    Ok(())
}

// Async: stop tears down the daemon TUN session (blocking socket I/O), so keep it off
// the event loop to avoid freezing the window during disconnect.
#[tauri::command]
async fn stop_proxy(
    app: AppHandle,
    tray: State<'_, TrayHandles>,
    state: State<'_, SharedRuntimeState>,
) -> Result<(), String> {
    stop_proxy_impl(&app, tray.inner(), state.inner())
}

fn stop_proxy_impl(
    app: &AppHandle,
    tray: &TrayHandles,
    state: &SharedRuntimeState,
) -> Result<(), String> {
    let mut config = load_or_default_config().map_err(|e| e.to_string())?;
    config.enabled = false;
    if config.selected_profile_id.is_none() {
        config.selected_profile_id = config.active_profile_id.clone();
    }
    config.save_default_path().map_err(|e| e.to_string())?;
    stop_runtime(app, tray, state)?;
    refresh_direct_exit_status_background(
        app.clone(),
        tray.clone(),
        state.clone(),
        config.tray_settings.clone(),
    );
    Ok(())
}

// Async: performs a network SOCKS5 handshake.
#[tauri::command]
async fn test_proxy(config: AppConfig, profile_id: String) -> Result<(), String> {
    let config = config.canonicalized().map_err(|e| e.to_string())?;
    let profile = config
        .resolve_profile_by_selector(Some(&profile_id))
        .map_err(|e| e.to_string())?;
    socks5::handshake(&profile.endpoint)
}

// Async: runs the exit-IP and geo network lookups.
#[tauri::command]
async fn refresh_exit_status(
    app: AppHandle,
    config: AppConfig,
    tray: State<'_, TrayHandles>,
    state: State<'_, SharedRuntimeState>,
) -> Result<crate::types::ExitStatus, String> {
    refresh_exit_status_impl(&app, tray.inner(), state.inner(), config)
}

fn refresh_exit_status_impl(
    app: &AppHandle,
    tray: &TrayHandles,
    state: &SharedRuntimeState,
    config: AppConfig,
) -> Result<crate::types::ExitStatus, String> {
    let config = config.canonicalized().map_err(|e| e.to_string())?;
    let selector = config
        .active_profile_id
        .as_deref()
        .or(config.selected_profile_id.as_deref());
    let profile = config
        .resolve_profile_by_selector(selector)
        .map_err(|e| e.to_string())?;
    let (profile, use_direct_lookup) = {
        let runtime = state
            .lock()
            .map_err(|_| "runtime lock poisoned".to_string())?;
        (
            effective_system_lookup_profile(&profile, runtime.local_system_proxy.is_some()),
            runtime.connection_state == ConnectionState::Stopped,
        )
    };
    let exit_status = if use_direct_lookup {
        lookup_exit_status_direct(&config.tray_settings)
    } else {
        lookup_exit_status(&profile, &config.tray_settings)
    };
    let snapshot = {
        let mut runtime = state
            .lock()
            .map_err(|_| "runtime lock poisoned".to_string())?;
        runtime.exit_status = exit_status.clone();
        RuntimeSnapshot::from(&*runtime)
    };
    update_tray_ui(app, tray, &snapshot);
    Ok(exit_status)
}

fn effective_system_lookup_profile(
    profile: &ResolvedProfile,
    local_proxy_active: bool,
) -> ResolvedProfile {
    #[cfg(not(any(target_os = "linux", target_os = "windows")))]
    let _ = local_proxy_active;

    #[cfg(any(target_os = "linux", target_os = "windows"))]
    if profile.routing_mode == RoutingMode::System && local_proxy_active {
        let mut effective = profile.clone();
        effective.endpoint = system_local_endpoint();
        return effective;
    }

    profile.clone()
}

// Async: diagnostics run a series of blocking network/route probes.
#[tauri::command]
async fn run_diagnostics(
    app: AppHandle,
    config: AppConfig,
    state: State<'_, SharedRuntimeState>,
) -> Result<DiagnosticReport, String> {
    diagnostics::run_diagnostics(state.inner(), config, move |event| {
        let _ = app.emit("diagnostics-progress", event);
    })
}

#[tauri::command]
fn list_desktop_apps() -> Result<Vec<proxy_core::desktop_entry::DesktopAppEntry>, String> {
    proxy_core::desktop_entry::discover_desktop_apps().map_err(|error| error.to_string())
}

#[tauri::command]
fn open_manage_window(app: AppHandle) -> Result<(), String> {
    ensure_manage_window(&app).map_err(|e| e.to_string())?;
    if let Some(window) = app.get_webview_window("manage") {
        let _ = window.show();
        let _ = window.set_focus();
    }
    Ok(())
}

fn main() {
    if handle_headless_command() {
        return;
    }
    #[cfg(target_os = "windows")]
    elevation::relaunch_elevated_if_needed();
    #[cfg(target_os = "windows")]
    std::env::set_var(proxy_platform_windows::ENABLE_WFP_MUTATION_ENV, "1");
    init_logging();
    let instance_lock = match SingleInstanceLock::acquire() {
        Ok(lock) => lock,
        Err(error) => {
            eprintln!("{error}");
            std::process::exit(0);
        }
    };

    tauri::Builder::default()
        .manage(Arc::new(Mutex::new(RuntimeState::default())))
        .manage(instance_lock)
        .setup(|app| {
            if let Err(error) = perform_startup_cleanup() {
                tracing::warn!(error = %error, "startup cleanup failed");
            }
            ensure_manage_window(app.handle())?;

            let status_item = MenuItem::with_id(
                app,
                MENU_STATUS_ID,
                "Status: Disconnected (no profile)",
                false,
                None::<&str>,
            )?;
            let exit_item =
                MenuItem::with_id(app, MENU_EXIT_ID, "Exit IP: —", false, None::<&str>)?;
            let action_item =
                MenuItem::with_id(app, MENU_ACTION_ID, "Connect", true, None::<&str>)?;
            let open = MenuItem::with_id(app, MENU_OPEN_ID, "Open Settings", true, None::<&str>)?;
            let quit = MenuItem::with_id(app, MENU_QUIT_ID, "Quit", true, None::<&str>)?;
            let menu =
                Menu::with_items(app, &[&status_item, &exit_item, &action_item, &open, &quit])?;

            TrayIconBuilder::with_id(TRAY_ID)
                .icon(connection_icon(TrayConnectionState::Disconnected, false))
                .menu(&menu)
                .show_menu_on_left_click(true)
                .on_menu_event(|app, event| match event.id().as_ref() {
                    MENU_ACTION_ID => {
                        let state = app.state::<SharedRuntimeState>();
                        let is_active = {
                            let runtime = state.lock().unwrap_or_else(|p| p.into_inner());
                            matches!(
                                runtime.connection_state,
                                ConnectionState::Connected
                                    | ConnectionState::Blocked
                                    | ConnectionState::Rebinding
                            )
                        };
                        let tray = app.state::<TrayHandles>();
                        if is_active {
                            if let Err(error) = stop_proxy_impl(app, tray.inner(), state.inner()) {
                                set_runtime_error(app, &error);
                            }
                        } else if let Err(error) = start_saved_active_profile(app) {
                            set_runtime_error(app, &error);
                        }
                    }
                    MENU_OPEN_ID => {
                        let _ = open_manage_window(app.clone());
                    }
                    MENU_QUIT_ID => app.exit(0),
                    _ => {}
                })
                .build(app)?;

            app.manage(TrayHandles {
                status_item,
                exit_item,
                action_item,
            });

            let runtime_state = app.state::<SharedRuntimeState>();
            let tray = app.state::<TrayHandles>();
            let snapshot = {
                let runtime = runtime_state
                    .lock()
                    .map_err(|_| "runtime lock poisoned")
                    .expect("runtime lock poisoned");
                RuntimeSnapshot::from(&*runtime)
            };
            update_tray_ui(app.handle(), tray.inner(), &snapshot);
            refresh_direct_exit_status_background(
                app.handle().clone(),
                tray.inner().clone(),
                runtime_state.inner().clone(),
                load_or_default_config()
                    .map(|config| config.tray_settings)
                    .unwrap_or_default(),
            );

            if let Some(window) = app.get_webview_window("manage") {
                let w = window.clone();
                window.on_window_event(move |event| {
                    if let WindowEvent::CloseRequested { api, .. } = event {
                        let _ = w.hide();
                        api.prevent_close();
                    }
                });
            }

            Ok(())
        })
        .invoke_handler(tauri::generate_handler![
            load_config,
            save_config,
            preview_raw_entries,
            start_proxy,
            stop_proxy,
            status,
            test_proxy,
            refresh_exit_status,
            run_diagnostics,
            list_desktop_apps,
            open_manage_window
        ])
        .run(tauri::generate_context!())
        .expect("failed to run SOCKS5 Proxy");
}

fn handle_headless_command() -> bool {
    let mut args = std::env::args();
    let _ = args.next();
    let command = args.next();
    #[cfg_attr(not(target_os = "windows"), allow(unused_variables))]
    let rest = args.collect::<Vec<_>>();
    match command.as_deref() {
        Some("--windows-tun-preflight-json") => {
            #[cfg(target_os = "windows")]
            {
                print_windows_tun_preflight_json();
            }
            #[cfg(not(target_os = "windows"))]
            {
                println!(
                    "{}",
                    serde_json::json!({
                        "ok": false,
                        "error": "windows TUN preflight is only available on Windows"
                    })
                );
            }
            true
        }
        Some("--windows-wfp-rollback-json") => {
            #[cfg(target_os = "windows")]
            {
                print_windows_wfp_rollback_json();
            }
            #[cfg(not(target_os = "windows"))]
            {
                println!(
                    "{}",
                    serde_json::json!({
                        "ok": false,
                        "error": "windows WFP rollback is only available on Windows"
                    })
                );
            }
            true
        }
        Some("--windows-wfp-apply-json") => {
            #[cfg(target_os = "windows")]
            {
                let proxy_ip = headless_arg_value(&rest, "--proxy-ip");
                print_windows_wfp_apply_json(proxy_ip.as_deref());
            }
            #[cfg(not(target_os = "windows"))]
            {
                println!(
                    "{}",
                    serde_json::json!({
                        "ok": false,
                        "error": "windows WFP apply is only available on Windows"
                    })
                );
            }
            true
        }
        Some("--windows-wfp-wintun-selftest-json") => {
            #[cfg(target_os = "windows")]
            {
                let proxy_ip = headless_arg_value(&rest, "--proxy-ip");
                let interface = headless_arg_value(&rest, "--interface");
                print_windows_wfp_wintun_selftest_json(proxy_ip.as_deref(), interface.as_deref());
            }
            #[cfg(not(target_os = "windows"))]
            {
                println!(
                    "{}",
                    serde_json::json!({
                        "ok": false,
                        "error": "windows WFP Wintun self-test is only available on Windows"
                    })
                );
            }
            true
        }
        Some("--windows-tun-session-e2e-json") => {
            #[cfg(target_os = "windows")]
            {
                let hold_seconds = headless_arg_value(&rest, "--hold-seconds")
                    .and_then(|value| value.parse::<u64>().ok())
                    .unwrap_or(8);
                let probe_url = headless_arg_value(&rest, "--probe-url")
                    .unwrap_or_else(|| "https://api.ipify.org".to_string());
                let profile_selector = headless_arg_value(&rest, "--profile");
                print_windows_tun_session_e2e_json(
                    hold_seconds,
                    &probe_url,
                    profile_selector.as_deref(),
                );
            }
            #[cfg(not(target_os = "windows"))]
            {
                println!(
                    "{}",
                    serde_json::json!({
                        "ok": false,
                        "error": "windows TUN session end-to-end test is only available on Windows"
                    })
                );
            }
            true
        }
        Some("--windows-tun-status-poll-json") => {
            #[cfg(target_os = "windows")]
            {
                let polls = headless_arg_value(&rest, "--polls")
                    .and_then(|value| value.parse::<u32>().ok())
                    .unwrap_or(8);
                let interval = headless_arg_value(&rest, "--interval-ms")
                    .and_then(|value| value.parse::<u64>().ok())
                    .unwrap_or(1500);
                let profile_selector = headless_arg_value(&rest, "--profile");
                print_windows_tun_status_poll_json(polls, interval, profile_selector.as_deref());
            }
            #[cfg(not(target_os = "windows"))]
            {
                println!(
                    "{}",
                    serde_json::json!({
                        "ok": false,
                        "error": "windows TUN status poll test is only available on Windows"
                    })
                );
            }
            true
        }
        Some("--help") | Some("-h") => {
            println!(
                "SOCKS5Proxy desktop\n\nOptions:\n  --windows-tun-preflight-json\n  --windows-wfp-rollback-json\n  --windows-wfp-apply-json [--proxy-ip <ip>]\n  --windows-wfp-wintun-selftest-json --interface <name> [--proxy-ip <ip>]\n  --windows-tun-session-e2e-json [--profile <id|name>] [--hold-seconds <n>] [--probe-url <url>]\n  --windows-tun-status-poll-json [--profile <id|name>] [--polls <n>] [--interval-ms <ms>]"
            );
            true
        }
        _ => false,
    }
}

#[cfg_attr(not(target_os = "windows"), allow(dead_code))]
fn headless_arg_value(args: &[String], name: &str) -> Option<String> {
    args.windows(2)
        .find(|pair| pair[0] == name)
        .map(|pair| pair[1].clone())
}

