#[cfg(target_os = "windows")]
fn print_windows_wfp_wintun_selftest_json(proxy_ip: Option<&str>, interface: Option<&str>) {
    let Some(interface) = interface else {
        println!(
            "{}",
            serde_json::json!({
                "ok": false,
                "error": "--interface <adapter name> is required for the Wintun egress self-test"
            })
        );
        return;
    };
    let mullvad = proxy_platform_windows::mullvad_status();
    let firewall = proxy_platform_windows::firewall_preflight();
    let wfp_exception_plan = proxy_platform_windows::wfp_exception_plan(&mullvad, &firewall);
    let wfp_operation_plan = proxy_platform_windows::wfp_operation_plan(&wfp_exception_plan);
    let wfp_apply_context = proxy_platform_windows::wfp_apply_context_for_mullvad_with_paths(
        proxy_ip,
        &mullvad,
        wfp_exception_plan.app_path.clone(),
        wfp_exception_plan.tun2proxy_path.clone(),
    );
    let wfp_apply_readiness = proxy_platform_windows::wfp_apply_readiness_with_context(
        &wfp_exception_plan,
        &wfp_operation_plan,
        &wfp_apply_context,
    );
    let report = proxy_platform_windows::wintun_egress_permit_selftest(
        &wfp_operation_plan,
        &wfp_apply_readiness,
        interface,
    );
    println!(
        "{}",
        serde_json::json!({
            "ok": report.ok,
            "mutation_env": proxy_platform_windows::ENABLE_WFP_MUTATION_ENV,
            "interface": report.interface,
            "luid": report.luid,
            "luid_hex": report.luid.map(|luid| format!("0x{luid:016x}")),
            "luid_error": report.luid_error,
            "phase1_status": report.phase1_status,
            "phase1_errors": report.phase1_errors,
            "wintun_applied": report.wintun_applied,
            "wintun_error": report.wintun_error,
            "rollback_status": report.rollback_status,
            "rollback_errors": report.rollback_errors,
        })
    );
}

/// End-to-end Z4 verification: bring up the full Windows TUN session (WFP exception +
/// tun2proxy + Wintun egress permit), then prove that this process — an ordinary app whose
/// traffic is routed into the proxy Wintun — can still reach the internet while Mullvad's
/// killswitch is active, and report the observed exit IP. Always tears the session back down.
#[cfg(target_os = "windows")]
fn print_windows_tun_session_e2e_json(hold_seconds: u64, probe_url: &str, profile_selector: Option<&str>) {
    let config = match load_or_default_config() {
        Ok(config) => config,
        Err(error) => {
            println!(
                "{}",
                serde_json::json!({ "ok": false, "phase": "config", "error": error.to_string() })
            );
            return;
        }
    };
    let selector = profile_selector
        .map(|value| value.to_string())
        .or_else(|| config.selected_profile_id.clone())
        .or_else(|| config.active_profile_id.clone())
        .or_else(|| config.profiles.first().map(|profile| profile.id.clone()));
    let mut profile = match config.resolve_profile_by_selector(selector.as_deref()) {
        Ok(profile) => profile,
        Err(error) => {
            println!(
                "{}",
                serde_json::json!({ "ok": false, "phase": "resolve_profile", "error": error.to_string() })
            );
            return;
        }
    };
    // This test only exercises the TUN path; force it regardless of the saved routing mode.
    profile.routing_mode = RoutingMode::Tun;

    let mutation_enabled = std::env::var(proxy_platform_windows::ENABLE_WFP_MUTATION_ENV)
        .map(|value| value == "1")
        .unwrap_or(false);

    let start = proxy_platform_windows::start_tun_session(&profile);
    let (start_value, started) = match &start {
        Ok(status) => (namespace_status_json(status), status.state == "connected"),
        Err(error) => (serde_json::json!({ "error": error.to_string() }), false),
    };

    // Self-probe only makes sense if the session actually came up.
    let mut exit_ip: Option<String> = None;
    let mut probe_error: Option<String> = None;
    let mut probe_attempts = 0u32;
    if started {
        match reqwest::blocking::Client::builder()
            .timeout(std::time::Duration::from_secs(10))
            .build()
        {
            Ok(client) => {
                let deadline_attempts = (hold_seconds / 2).max(1) as u32 + 1;
                for attempt in 0..deadline_attempts {
                    probe_attempts = attempt + 1;
                    match client.get(probe_url).send().and_then(|response| response.text()) {
                        Ok(body) => {
                            exit_ip = Some(body.trim().to_string());
                            probe_error = None;
                            break;
                        }
                        Err(error) => {
                            probe_error = Some(error.to_string());
                            std::thread::sleep(std::time::Duration::from_secs(2));
                        }
                    }
                }
            }
            Err(error) => probe_error = Some(format!("failed to build HTTP client: {error}")),
        }
    }

    // Always tear the session back down, even if the probe failed.
    let stop = proxy_platform_windows::stop_tun_session();
    let stop_value = match &stop {
        Ok(status) => namespace_status_json(status),
        Err(error) => serde_json::json!({ "error": error.to_string() }),
    };

    let ok = started && exit_ip.is_some() && stop.is_ok();
    println!(
        "{}",
        serde_json::json!({
            "ok": ok,
            "mutation_env": proxy_platform_windows::ENABLE_WFP_MUTATION_ENV,
            "mutation_enabled": mutation_enabled,
            "profile_name": profile.name,
            "proxy_host": profile.endpoint.host,
            "probe_url": probe_url,
            "probe_attempts": probe_attempts,
            "exit_ip": exit_ip,
            "probe_error": probe_error,
            "session_started": started,
            "start": start_value,
            "stop": stop_value,
        })
    );
}

/// Reproduce the GUI's live behavior: start a TUN session, then repeatedly poll
/// `tun_status()` exactly like the `status` command does on every frontend tick.
/// The e2e command never polls, so the live path (`reconcile_proxy_vpn_route` +
/// `vpn_chain_block_reason` -> possible "blocked" -> auto-stop) is only exercised
/// here. If any poll reports something other than "connected", that is the GUI bug.
#[cfg(target_os = "windows")]
fn print_windows_tun_status_poll_json(polls: u32, interval_ms: u64, profile_selector: Option<&str>) {
    let config = match load_or_default_config() {
        Ok(config) => config,
        Err(error) => {
            println!(
                "{}",
                serde_json::json!({ "ok": false, "phase": "config", "error": error.to_string() })
            );
            return;
        }
    };
    let selector = profile_selector
        .map(|value| value.to_string())
        .or_else(|| config.selected_profile_id.clone())
        .or_else(|| config.active_profile_id.clone())
        .or_else(|| config.profiles.first().map(|profile| profile.id.clone()));
    let mut profile = match config.resolve_profile_by_selector(selector.as_deref()) {
        Ok(profile) => profile,
        Err(error) => {
            println!(
                "{}",
                serde_json::json!({ "ok": false, "phase": "resolve_profile", "error": error.to_string() })
            );
            return;
        }
    };
    profile.routing_mode = RoutingMode::Tun;

    let start = proxy_platform_windows::start_tun_session(&profile);
    let (start_value, started) = match &start {
        Ok(status) => (namespace_status_json(status), status.state == "connected"),
        Err(error) => (serde_json::json!({ "error": error.to_string() }), false),
    };

    // Exercise the exact exit-IP lookup the GUI poller uses, so we verify the
    // TUN-mode (direct client + DNS-free trace) path end-to-end.
    let exit_status = if started {
        Some(crate::geo::lookup_exit_status(&profile, &config.tray_settings))
    } else {
        None
    };
    let exit_status_value = exit_status.as_ref().map(|status| {
        serde_json::json!({
            "exit_ip": status.exit_ip,
            "country_code": status.country_code,
            "country_flag": status.country_flag,
            "lookup_error": status.lookup_error,
        })
    });

    // DNS diagnosis: resolve a hostname through the OS resolver (which harden_dns
    // points at the virtual resolver 10.0.0.1) and separately query 10.0.0.1:53
    // directly via UDP, so we can tell whether the virtual DNS responds at all and
    // whether name resolution is blocked vs. the resolved IP being unroutable.
    let dns_probe = if started {
        use std::net::ToSocketAddrs;
        let os_resolve = match ("api.ipify.org", 443u16).to_socket_addrs() {
            Ok(addrs) => {
                let ips: Vec<String> = addrs.map(|a| a.ip().to_string()).collect();
                serde_json::json!({ "ok": true, "resolved": ips })
            }
            Err(error) => serde_json::json!({ "ok": false, "error": error.to_string() }),
        };
        Some(serde_json::json!({
            "os_resolver": os_resolve,
            "udp_10_0_0_1": dns_query_udp("10.0.0.1:53", "api.ipify.org"),
            "udp_mullvad_10_64_0_1": dns_query_udp("10.64.0.1:53", "api.ipify.org"),
            "udp_external_1_1_1_1": dns_query_udp("1.1.1.1:53", "api.ipify.org"),
        }))
    } else {
        None
    };

    // Prove the local->remote-proxy hop rides INSIDE the Mullvad tunnel: generate
    // sustained traffic so tun2proxy holds a connection open to the proxy server,
    // then inspect that socket's LOCAL source address. It must be the Mullvad
    // tunnel-internal IP (not a physical interface), which means the proxy
    // connection is encapsulated by Mullvad rather than leaking around it.
    let proxy_link = if started {
        let proxy_ip = start.as_ref().ok().and_then(|s| s.proxy_ip.clone());
        if let Some(proxy_ip) = proxy_ip {
            // Sustained traffic in a background thread so the proxy socket stays up
            // while we snapshot the TCP table.
            let traffic = std::thread::spawn(|| {
                if let Ok(client) = reqwest::blocking::Client::builder()
                    .timeout(std::time::Duration::from_secs(6))
                    .build()
                {
                    for _ in 0..6 {
                        let _ = client
                            .get("https://speed.cloudflare.com/__down?bytes=4000000")
                            .send()
                            .and_then(|r| r.bytes());
                    }
                }
            });
            std::thread::sleep(std::time::Duration::from_millis(1500));
            let snapshot = tcp_connections_to(&proxy_ip);
            let _ = traffic.join();
            Some(serde_json::json!({
                "proxy_ip": proxy_ip,
                "mullvad_tunnel_hint": "Mullvad source IP = inside tunnel; physical NIC IP = leak",
                "connections": snapshot,
            }))
        } else {
            None
        }
    } else {
        None
    };

    let mut poll_states: Vec<serde_json::Value> = Vec::new();
    if started {
        for index in 0..polls {
            std::thread::sleep(std::time::Duration::from_millis(interval_ms));
            match proxy_platform_windows::tun_status() {
                Ok(status) => poll_states.push(serde_json::json!({
                    "poll": index + 1,
                    "state": status.state,
                    "proxy_uplink_interface": status.proxy_uplink_interface,
                    "host_vpn_interface": status.host_vpn_interface,
                    "last_reason": status.last_reason,
                    "last_error": status.last_error,
                })),
                Err(error) => poll_states.push(serde_json::json!({
                    "poll": index + 1,
                    "error": error.to_string(),
                })),
            }
        }
    }

    let stayed_connected = started
        && poll_states.iter().all(|poll| {
            poll.get("state").and_then(|s| s.as_str()) == Some("connected")
        });

    let stop = proxy_platform_windows::stop_tun_session();
    let stop_value = match &stop {
        Ok(status) => namespace_status_json(status),
        Err(error) => serde_json::json!({ "error": error.to_string() }),
    };

    println!(
        "{}",
        serde_json::json!({
            "ok": stayed_connected && stop.is_ok(),
            "session_started": started,
            "stayed_connected": stayed_connected,
            "profile_name": profile.name,
            "start": start_value,
            "exit_status": exit_status_value,
            "dns_probe": dns_probe,
            "proxy_link": proxy_link,
            "polls": poll_states,
            "stop": stop_value,
        })
    );
}

/// Snapshot established TCP connections to `proxy_ip` via Get-NetTCPConnection,
/// reporting each socket's local (source) address so we can confirm the proxy hop
/// originates from the Mullvad tunnel interface, not a physical NIC.
#[cfg(target_os = "windows")]
fn tcp_connections_to(proxy_ip: &str) -> serde_json::Value {
    let script = format!(
        "Get-NetTCPConnection -RemoteAddress '{proxy_ip}' -ErrorAction SilentlyContinue | \
         ForEach-Object {{ \"{{0}}|{{1}}|{{2}}|{{3}}|{{4}}\" -f \
         $_.LocalAddress,$_.LocalPort,$_.RemotePort,$_.State,\
         (Get-Process -Id $_.OwningProcess -ErrorAction SilentlyContinue).ProcessName }}"
    );
    let output = crate::util::console_hidden_command("powershell")
        .args(["-NoProfile", "-Command", &script])
        .output();
    match output {
        Ok(out) => {
            let text = String::from_utf8_lossy(&out.stdout);
            let rows: Vec<serde_json::Value> = text
                .lines()
                .filter(|line| !line.trim().is_empty())
                .map(|line| {
                    let f: Vec<&str> = line.split('|').collect();
                    serde_json::json!({
                        "local_address": f.first().copied().unwrap_or(""),
                        "local_port": f.get(1).copied().unwrap_or(""),
                        "remote_port": f.get(2).copied().unwrap_or(""),
                        "state": f.get(3).copied().unwrap_or(""),
                        "process": f.get(4).copied().unwrap_or(""),
                    })
                })
                .collect();
            serde_json::json!(rows)
        }
        Err(error) => serde_json::json!({ "error": error.to_string() }),
    }
}

/// Send a minimal DNS A-query for `host` to `server` over UDP and report the
/// outcome. Used to test whether tun2proxy's virtual resolver at 10.0.0.1 answers
/// at all (vs. the query being blocked, e.g. by Mullvad's DNS enforcement).
#[cfg(target_os = "windows")]
fn dns_query_udp(server: &str, host: &str) -> serde_json::Value {
    use std::net::UdpSocket;
    let mut query = Vec::new();
    query.extend_from_slice(&[0x12, 0x34]); // id
    query.extend_from_slice(&[0x01, 0x00]); // flags: recursion desired
    query.extend_from_slice(&[0x00, 0x01, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00]); // 1 question
    for label in host.split('.') {
        query.push(label.len() as u8);
        query.extend_from_slice(label.as_bytes());
    }
    query.push(0);
    query.extend_from_slice(&[0x00, 0x01]); // type A
    query.extend_from_slice(&[0x00, 0x01]); // class IN

    let socket = match UdpSocket::bind("0.0.0.0:0") {
        Ok(socket) => socket,
        Err(error) => return serde_json::json!({ "ok": false, "phase": "bind", "error": error.to_string() }),
    };
    let _ = socket.set_read_timeout(Some(std::time::Duration::from_secs(4)));
    if let Err(error) = socket.send_to(&query, server) {
        return serde_json::json!({ "ok": false, "phase": "send", "error": error.to_string() });
    }
    let mut buf = [0u8; 512];
    match socket.recv_from(&mut buf) {
        Ok((len, _)) => {
            let answers = if len >= 8 { ((buf[6] as u16) << 8) | buf[7] as u16 } else { 0 };
            serde_json::json!({ "ok": true, "response_bytes": len, "answer_count": answers })
        }
        Err(error) => serde_json::json!({ "ok": false, "phase": "recv", "error": error.to_string() }),
    }
}

#[cfg(target_os = "windows")]
fn namespace_status_json(status: &proxy_core::NamespaceSessionStatus) -> serde_json::Value {
    serde_json::json!({
        "state": status.state,
        "profile_name": status.profile_name,
        "proxy_ip": status.proxy_ip,
        "tun2proxy_pid": status.tun2proxy_pid,
        "host_vpn_interface": status.host_vpn_interface,
        "proxy_uplink_interface": status.proxy_uplink_interface,
        "last_error": status.last_error,
        "last_reason": status.last_reason,
        "wfp_filter_count": status.wfp_filters.len(),
    })
}

#[cfg(target_os = "windows")]
fn windows_z4_guard_json(
    status: &proxy_platform_windows::WindowsMullvadStatus,
) -> serde_json::Value {
    let connected = status
        .state
        .as_deref()
        .map(|state| state.to_ascii_lowercase().starts_with("connected"))
        .unwrap_or(false);

    if connected {
        let endpoint = status
            .endpoint_address
            .as_deref()
            .or(status.relay_hostname.as_deref())
            .unwrap_or("unknown endpoint");
        return serde_json::json!({
            "status": "blocked",
            "blocked": true,
            "reason": format!("Mullvad is connected ({endpoint}). Windows Z4 requires the scoped WFP kill-switch exception before TUN routing can start. The exception is applied only when SOCKS5PROXY_ENABLE_WFP_MUTATION=1 is set in an elevated guarded session."),
            "mutation_env": proxy_platform_windows::ENABLE_WFP_MUTATION_ENV
        });
    }

    if let Some(error) = status.error.as_deref() {
        return serde_json::json!({
            "status": "warn",
            "blocked": false,
            "reason": format!("Mullvad status could not be verified: {error}"),
            "mutation_env": proxy_platform_windows::ENABLE_WFP_MUTATION_ENV
        });
    }

    serde_json::json!({
        "status": "pass",
        "blocked": false,
        "reason": "No connected Mullvad tunnel is active; guarded Z2 live testing is not blocked by the Z4 WFP guard.",
        "mutation_env": proxy_platform_windows::ENABLE_WFP_MUTATION_ENV
    })
}

#[cfg(target_os = "windows")]
fn guard_windows_wireguard_killswitch() -> Result<(), String> {
    let status = proxy_platform_windows::wireguard_status();
    if status.interfaces.is_empty() {
        return Ok(());
    }

    if status.locked_down == Some(true) {
        let reason = status
            .lockdown_reason
            .as_deref()
            .unwrap_or("WireGuard firewall block rules are active");
        return Err(format!(
            "Windows Z3 with WireGuard kill-switch enabled is intentionally blocked in V1. Disable WireGuard's \"Block untunneled traffic\" option for Z3, or use the future Z3b/Z4 WFP exception path. Detected: {reason}"
        ));
    }

    Ok(())
}

fn init_logging() {
    use tracing_subscriber::EnvFilter;
    let filter =
        EnvFilter::try_from_env("SOCKS5PROXY_LOG").unwrap_or_else(|_| EnvFilter::new("info"));
    let _ = tracing_subscriber::fmt()
        .with_env_filter(filter)
        .with_target(false)
        .with_writer(std::io::stderr)
        .try_init();
}

fn load_or_default_config() -> Result<AppConfig, ConfigError> {
    match AppConfig::load_default_path() {
        Ok(config) => Ok(config),
        Err(ConfigError::Io(error)) if error.kind() == std::io::ErrorKind::NotFound => {
            Ok(AppConfig::default())
        }
        Err(error) => Err(error),
    }
}

fn start_saved_active_profile(app: &AppHandle) -> Result<(), String> {
    let config = load_or_default_config().map_err(|e| e.to_string())?;
    let profile_id = config
        .selected_profile_id
        .clone()
        .or_else(|| config.active_profile_id.clone())
        .or_else(|| config.profiles.first().map(|profile| profile.id.clone()))
        .ok_or_else(|| "no saved profile is available to connect".to_string())?;
    let tray = app.state::<TrayHandles>();
    let state = app.state::<SharedRuntimeState>();
    start_proxy_background(app, tray.inner(), state.inner(), config, profile_id)
}

fn ensure_manage_window(app: &AppHandle) -> tauri::Result<()> {
    if app.get_webview_window("manage").is_some() {
        return Ok(());
    }

    WebviewWindowBuilder::new(app, "manage", WebviewUrl::App("index.html".into()))
        .title("SOCKS5 Proxy Settings")
        .inner_size(980.0, 760.0)
        .visible(false)
        .build()?;

    Ok(())
}

fn set_runtime_error(app: &AppHandle, message: &str) {
    if let Some(runtime_state) = app.try_state::<SharedRuntimeState>() {
        if let Ok(mut runtime) = runtime_state.lock() {
            runtime.connection_state = ConnectionState::Error;
            runtime.last_error = Some(message.to_string());
            let snapshot = RuntimeSnapshot::from(&*runtime);
            if let Some(tray) = app.try_state::<TrayHandles>() {
                update_tray_ui(app, tray.inner(), &snapshot);
            }
        }
    }
    tracing::error!(error = %message, "tray action failed");
}

fn refresh_direct_exit_status_background(
    app: AppHandle,
    tray: TrayHandles,
    state: SharedRuntimeState,
    tray_settings: TraySettings,
) {
    if !tray_settings.exit_ip_lookup_enabled {
        return;
    }

    std::thread::spawn(move || {
        let should_refresh = state
            .lock()
            .map(|runtime| runtime.connection_state == ConnectionState::Stopped)
            .unwrap_or(false);
        if !should_refresh {
            return;
        }

        let exit_status = lookup_exit_status_direct(&tray_settings);
        let snapshot = {
            let mut runtime = match state.lock() {
                Ok(runtime) => runtime,
                Err(_) => return,
            };
            if runtime.connection_state != ConnectionState::Stopped {
                return;
            }
            runtime.exit_status = exit_status;
            RuntimeSnapshot::from(&*runtime)
        };
        update_tray_ui(&app, &tray, &snapshot);
    });
}

fn sync_runtime_with_tun_status(runtime: &mut RuntimeState) {
    match tun_backend::status() {
        Ok(status) => {
            // A connect runs on a background thread; until it finishes start_tun_session
            // and stores the session, the slot is empty and tun_status() reports
            // "stopped". While we are still Rebinding, that means "starting", not
            // "disconnected" — don't flip the UI to "Disconnected" for those seconds.
            // The start thread will move us to Connected (success) or Error (failure).
            if status.state == "stopped"
                && runtime.connection_state == ConnectionState::Rebinding
            {
                return;
            }
            let blocked = status.state == "blocked";
            apply_tun_daemon_status(runtime, &status);
            if blocked {
                let _ = tun_backend::stop();
                if let Some(artifacts) = runtime.runtime_artifacts.take() {
                    if let Err(error) = cleanup_runtime_artifacts(&artifacts) {
                        runtime.connection_state = ConnectionState::Error;
                        runtime.last_error = Some(format!(
                            "Windows TUN was blocked for VPN safety, but cleanup failed: {error}"
                        ));
                    }
                }
                runtime.current_session_id = None;
            }
        }
        Err(error) => {
            // The daemon is unreachable (stopped or crashed) while we still believe a
            // TUN session is active. Reflect that as an error state instead of bubbling
            // the error up: `status` is polled by the GUI, which swallows command
            // errors, so propagating here would freeze the UI on the last good
            // (Connected) snapshot. Surfacing Error keeps the GUI and tray consistent
            // and self-heals once the daemon answers again.
            runtime.connection_state = ConnectionState::Error;
            runtime.last_error = Some(format!("socks5proxy daemon is not reachable: {error}"));
            runtime.traffic_flow = network::build_traffic_flow(
                runtime.active_profile.as_ref(),
                &runtime.vpn_status,
                runtime.connection_state,
            );
        }
    }
}

fn apply_tun_daemon_status(
    runtime: &mut RuntimeState,
    status: &proxy_core::NamespaceSessionStatus,
) {
    runtime.connection_state = match status.state.as_str() {
        "connected" => ConnectionState::Connected,
        "blocked" => ConnectionState::Blocked,
        "error" => ConnectionState::Error,
        "starting" => ConnectionState::Rebinding,
        _ => ConnectionState::Stopped,
    };
    runtime.last_error = status.last_error.clone();
    runtime.vpn_status.state = status.state.clone();
    runtime.vpn_status.vpn_interface = status.host_vpn_interface.clone();
    runtime.vpn_status.proxy_uplink_interface = status.proxy_uplink_interface.clone();
    runtime.vpn_status.last_reason = status.last_reason.clone();
    runtime.traffic_flow = network::build_traffic_flow(
        runtime.active_profile.as_ref(),
        &runtime.vpn_status,
        runtime.connection_state,
    );
    if let Some(artifacts) = runtime.runtime_artifacts.as_mut() {
        artifacts.proxy_pid = status.tun2proxy_pid;
        artifacts.bound_vpn_interface = status.host_vpn_interface.clone();
        artifacts.pinned_proxy_routes = status.pinned_proxy_routes.clone();
        artifacts.wfp_filters = status.wfp_filters.clone();
    }
}
